Core game data structures for the Chinese Checkers environment.

The board uses a 2D grid coordinate system with axial directions.

Directions are indexed 0-5:
  0 = UpLeft    (dq=-1, dr=0)
  1 = UpRight   (dq=0,  dr=-1)
  2 = Left      (dq=-1, dr=1)
  3 = Right     (dq=1,  dr=-1)
  4 = DownLeft  (dq=0,  dr=1)
  5 = DownRight (dq=1,  dr=0)

For triangle_size=n:
  Board spans q in [-2n, 2n], r in [-2n, 2n]
  Stored as (q + 2n, r + 2n) in a (4n+1)x(4n+1) array.
"""

from enum import IntEnum
from typing import Optional


class Direction(IntEnum):
    UpLeft    = 0
    UpRight   = 1
    Left      = 2
    Right     = 3
    DownLeft  = 4
    DownRight = 5


# Direction vectors in (dq, dr)
DIRECTION_VECTORS = {
    Direction.UpLeft:    (-1,  0),
    Direction.UpRight:   ( 0, -1),
    Direction.Left:      (-1,  1),
    Direction.Right:     ( 1, -1),
    Direction.DownLeft:  ( 0,  1),
    Direction.DownRight: ( 1,  0),
}


class Position:
    __slots__ = ('q', 'r')

    def __init__(self, q: int, r: int):
        self.q = q
        self.r = r

    def neighbor(self, direction) -> 'Position':
        dq, dr = DIRECTION_VECTORS[direction]
        return Position(self.q + dq, self.r + dr)

    def jump_target(self, direction) -> 'Position':
        dq, dr = DIRECTION_VECTORS[direction]
        return Position(self.q + 2 * dq, self.r + 2 * dr)

    def __eq__(self, other):
        if not isinstance(other, Position):
            return False
        return self.q == other.q and self.r == other.r

    def __hash__(self):
        return hash((self.q, self.r))

    def __repr__(self):
        return f"Position({self.q}, {self.r})"


class Move:
    """
    Represents a single move action.

    Constructor: Move(q, r, direction, is_jump)
      - q, r: position of the piece to move
      - direction: Direction enum value (int 0-5)
      - is_jump: True for jumps, False for steps

    Special sentinel: Move.END_TURN  (end the multi-jump sequence)
    """
    __slots__ = ('position', 'direction', 'is_jump', '_is_end_turn')

    def __init__(self, q=None, r=None, direction=None, is_jump=False, _end_turn=False):
        self._is_end_turn = _end_turn
        if _end_turn:
            self.position = None
            self.direction = None
            self.is_jump = False
        else:
            self.position = Position(q, r)
            self.direction = direction
            self.is_jump = is_jump

    def __eq__(self, other):
        if not isinstance(other, Move):
            return False
        if self._is_end_turn and other._is_end_turn:
            return True
        if self._is_end_turn or other._is_end_turn:
            return False
        return (self.position == other.position and
                self.direction == other.direction and
                self.is_jump == other.is_jump)

    def __hash__(self):
        if self._is_end_turn:
            return hash(('END_TURN',))
        return hash((self.position, self.direction, self.is_jump))

    def __repr__(self):
        if self._is_end_turn:
            return "Move.END_TURN"
        return f"Move(pos={self.position}, dir={self.direction}, jump={self.is_jump})"


# Create the END_TURN sentinel
Move.END_TURN = Move(_end_turn=True)
